#include <stdio.h>
#include <signal.h>
#include <unistd.h>

void sigint_handler(int sig) {
 printf("\nReceived SIGINT (Signal %d)\n", sig);
 printf("Handler executing - signals blocked during this time\n");
}

int main() {
 struct sigaction sa;

 // Initialize signal set and action structure
 sigemptyset(&sa.sa_mask);
 sigaddset(&sa.sa_mask, SIGTERM); // Block SIGTERM during handler

 sa.sa_handler = sigint_handler;
 sa.sa_flags = SA_RESTART; // Restart interrupted syscalls

 if (sigaction(SIGINT, &sa, NULL) == -1) {
 perror("sigaction failed");
 return 1;
 }

 printf("PID: %d\n", getpid());
 printf("Press Ctrl+C to send SIGINT\n");

 // Infinite loop - wait for signal
 while(1) {
 pause(); // Suspend until signal arrives
 }

 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <unistd.h>
#include <setjmp.h>

static sigjmp_buf jump_buffer;
static volatile sig_atomic_t jump_enabled = 0;

void alarm_handler(int sig) {
 if (jump_enabled) {
 printf("\nTimeout! Jumping back to safe point\n");
 siglongjmp(jump_buffer, 1);
 }
}

int main() {
 sigset_t mask, oldmask;
 struct sigaction sa;

 // Setup alarm handler
 sa.sa_handler = alarm_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGALRM, &sa, NULL);

 printf("Starting critical operation with timeout...\n");

 // Block SIGALRM
 sigemptyset(&mask);
 sigaddset(&mask, SIGALRM);
 sigprocmask(SIG_BLOCK, &mask, &oldmask);

 // Set timeout alarm
 alarm(3);

 if (sigsetjmp(jump_buffer, 1) == 0) {
 jump_enabled = 1;

 // CRITICAL SECTION - temporarily change mask
 sigsuspend(&oldmask); // Atomically: set old mask + wait

 // Simulate critical work
 printf("Processing critical section...\n");
 sleep(1);
 printf("Critical section completed\n");

 jump_enabled = 0;
 }

 // Restore original mask
 sigprocmask(SIG_SETMASK, &oldmask, NULL);

 printf("Program continues normally\n");
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>

static volatile sig_atomic_t keep_running = 1;

void sigterm_handler(int sig) {
 // Signal-safe: only set volatile variable
 keep_running = 0;
}

void setup_signals(void) {
 struct sigaction sa;

 sa.sa_handler = sigterm_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;

 // Handle SIGTERM for graceful shutdown
 sigaction(SIGTERM, &sa, NULL);

 // Handle SIGHUP for configuration reload
 sa.sa_handler = sighup_handler;
 sigaction(SIGHUP, &sa, NULL);

 // Ignore SIGTTIN and SIGTTOU (background process I/O)
 signal(SIGTTIN, SIG_IGN);
 signal(SIGTTOU, SIG_IGN);
}

void daemonize(const char *pidfile) {
 pid_t pid;
 int fd;

 pid = fork();
 if (pid < 0) exit(1);
 if (pid > 0) exit(0); // Parent exits

 // Child becomes session leader
 setsid();

 // Prevent acquiring a controlling terminal
 signal(SIGCHLD, SIG_IGN);

 pid = fork();
 if (pid < 0) exit(1);
 if (pid > 0) exit(0); // First child exits

 // Change working directory
 chdir("/");

 // Close standard file descriptors
 close(STDIN_FILENO);
 close(STDOUT_FILENO);
 close(STDERR_FILENO);

 // Open /dev/null for stdin, stdout, stderr
 fd = open("/dev/null", O_RDWR);
 dup(fd); dup(fd);

 // Write PID file
 if (pidfile) {
 FILE *pf = fopen(pidfile, "w");
 if (pf) {
 fprintf(pf, "%d\n", getpid());
 fclose(pf);
 }
 }
}

int main(int argc, char *argv[]) {
 if (argc > 1 && strcmp(argv[1], "-d") == 0) {
 daemonize("/var/run/myservice.pid");
 }

 setup_signals();

 while (keep_running) {
 // Main daemon work
 printf("Daemon running...\n");
 sleep(10);
 }

 printf("Daemon shutting down gracefully\n");
 return 0;
}
